import sys
class Solution:
    def findMST(self, edges: list[list[int]], V: int) -> int:
        parent = list(range(V))
        rank = [0] * V
        edges.sort(key=lambda x: x[2])
        def find(u):
            if parent[u] != u:
                parent[u] = find(parent[u])
            return parent[u]
        def union(u, v):
            root_u, root_v = find(u), find(v)
            if root_u != root_v:
                if rank[root_u] > rank[root_v]:
                    parent[root_v] = root_u
                else:
                    parent[root_u] = root_v
                    if rank[root_u] == rank[root_v]:
                        rank[root_v] += 1
        mst_cost = 0
        for u, v, w in edges:
            if find(u) != find(v):
                union(u, v)
                mst_cost += w
        return mst_cost
