#include <numeric>
#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    int findMST(vector<vector<int>>& edges, int V) {
        vector<int> parent(V);
        vector<int> rank(V, 0);
        for (int i = 0; i < V; i++) {
            parent[i] = i;
        }
        sort(edges.begin(), edges.end(), [](const vector<int>& a, const vector<int>& b) {
            return a[2] < b[2];
        });
        function<int(int)> find = [&](int u) {
            if (parent[u] != u) {
                parent[u] = find(parent[u]);
            }
            return parent[u];
        };
        function<void(int, int)> union_ = [&](int u, int v) {
            int root_u = find(u), root_v = find(v);
            if (root_u != root_v) {
                if (rank[root_u] > rank[root_v]) {
                    parent[root_v] = root_u;
                } else {
                    parent[root_u] = root_v;
                    if (rank[root_u] == rank[root_v]) {
                        rank[root_v] += 1;
                    }
                }
            }
        };
        int mst_cost = 0;
        for (const auto& edge : edges) {
            int u = edge[0], v = edge[1], w = edge[2];
            if (find(u) != find(v)) {
                union_(u, v);
                mst_cost += w;
            }
        }
        return mst_cost;
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    cin >> V >> E;
    vector<vector<int>> edges(E, vector<int>(3));
    for (int i = 0; i < E; i++) {
        cin >> edges[i][0] >> edges[i][1] >> edges[i][2];
    }
    Solution sol;
    int ans = sol.findMST(edges, V);
    cout << ans << '\n';
    return 0;
}
